# ---------------------------------------------------------------------------
# Heading helper with TOC bookmark
# ---------------------------------------------------------------------------

def add_heading(text: str, style: ParagraphStyle, level: int = 0, story: list = None):
    key = f'h_{hashlib.md5(text.encode()).hexdigest()[:10]}'
    p = Paragraph(f'<a name="{key}"/>{text}', style)
    p.bookmark_name = key
    p.bookmark_level = level
    p.bookmark_text = text
    p.bookmark_key = key
    if story is not None:
        story.append(p)
    return p


