class CalloutBox(Flowable):
    """A colored callout box with a title and message."""
    def __init__(self, title: str, message: str, color=ACCENT, width=None):
        super().__init__()
        self.title = title
        self.message = message
        self.color = color
        self._width = width
        self._title_p = Paragraph(f'<b>{title}</b>', ParagraphStyle(
            'CT', fontName=BODY_FONT_BOLD, fontSize=10.5, textColor=colors.white, leading=14))
        self._msg_p = Paragraph(message, ParagraphStyle(
            'CM', fontName=BODY_FONT, fontSize=9.5, textColor=TEXT_PRIMARY, leading=13))

    def wrap(self, availWidth, availHeight):
        self.width = self._width or availWidth
        self._title_p.wrap(self.width - 16, 30)
        self._msg_p.wrap(self.width - 16, 100)
        self.height = self._title_p.height + self._msg_p.height + 16
        return self.width, self.height

    def draw(self):
        c = self.canv
        # Title bar
        c.setFillColor(self.color)
        c.rect(0, self.height - self._title_p.height - 8, self.width, self._title_p.height + 8, fill=1, stroke=0)
        # Body
        c.setFillColor(CARD_BG)
        c.rect(0, 0, self.width, self.height - self._title_p.height - 8, fill=1, stroke=0)
        # Border
        c.setStrokeColor(self.color)
        c.setLineWidth(0.5)
        c.rect(0, 0, self.width, self.height, fill=0, stroke=1)
        # Title text
        self._title_p.drawOn(c, 8, self.height - self._title_p.height - 6)
        # Message
        self._msg_p.drawOn(c, 8, 8)


class StatBar(Flowable):
    """A horizontal stat bar: label, value, fraction."""
    def __init__(self, label: str, value: str, fraction: float, color=ACCENT, width=None):
        super().__init__()
        self.label = label
        self.value = value
        self.fraction = max(0.0, min(1.0, fraction))
        self.color = color
        self._width = width

    def wrap(self, availWidth, availHeight):
        self.width = self._width or availWidth
        self.height = 26
        return self.width, self.height

    def draw(self):
        c = self.canv
        # Label
        c.setFillColor(TEXT_PRIMARY)
        c.setFont(BODY_FONT_BOLD, 9)
        c.drawString(0, 14, self.label)
        # Value
        c.setFillColor(TEXT_MUTED)
        c.setFont(BODY_FONT, 9)
        c.drawRightString(self.width, 14, self.value)
        # Bar background
        c.setFillColor(CARD_BG)
        c.rect(0, 0, self.width, 8, fill=1, stroke=0)
        # Bar fill
        c.setFillColor(self.color)
        c.rect(0, 0, self.width * self.fraction, 8, fill=1, stroke=0)


def hr(color=BORDER, thickness=0.4, space_before=4, space_after=4):
    return HRFlowable(width='100%', thickness=thickness, color=color,
                      spaceBefore=space_before, spaceAfter=space_after)


# ---------------------------------------------------------------------------
# Page templates
# ---------------------------------------------------------------------------

def on_page(canv, doc):
    """Footer + header on every body page."""
    canv.saveState()
    page_w, page_h = A4
    # Top hairline
    canv.setStrokeColor(BORDER)
    canv.setLineWidth(0.4)
    canv.line(20*mm, page_h - 14*mm, page_w - 20*mm, page_h - 14*mm)
    # Top label
    canv.setFont(BODY_FONT, 8)
    canv.setFillColor(TEXT_MUTED)
    canv.drawString(20*mm, page_h - 12*mm, 'ATHENA-X · Stage 16.1 — Plugin Verification & Certification Report')
    canv.drawRightString(page_w - 20*mm, page_h - 12*mm, 'Confidential — Verification Audit')
    # Bottom hairline
    canv.line(20*mm, 14*mm, page_w - 20*mm, 14*mm)
    # Page number
    canv.setFont(BODY_FONT, 8)
    canv.setFillColor(TEXT_MUTED)
    canv.drawString(20*mm, 10*mm, 'v0.1.0-rc1 · Architecture Freeze')
    canv.drawRightString(page_w - 20*mm, 10*mm, f'Page {canv.getPageNumber()}')
    canv.restoreState()


class TocDocTemplate(SimpleDocTemplate):
    def afterFlowable(self, flowable):
        if hasattr(flowable, 'bookmark_name'):
            level = getattr(flowable, 'bookmark_level', 0)
            text = getattr(flowable, 'bookmark_text', '')
            key = getattr(flowable, 'bookmark_key', '')
            self.notify('TOCEntry', (level, text, self.page, key))


