        ('PLUGINS', f"{p['FAILED']} FAILED · {p['PROVISIONAL']} PROVISIONAL · {p['VERIFIED']} VERIFIED · {p['total']} total",
         SEM_ERROR),
        ('ENGINES', f"{e['FAILED']} FAILED · {e['PROVISIONAL']} PROVISIONAL · {e['VERIFIED']} VERIFIED · {e['total']} total",
         SEM_WARNING),
